import{_ as o}from"./chunks/api-module.da8b74fa.js";import{_ as s}from"./chunks/module-name.24651541.js";import{_ as a,o as c,c as l,O as p}from"./chunks/framework.3442b110.js";const h=JSON.parse('{"title":"核心知识","description":"","frontmatter":{},"headers":[],"relativePath":"zh/start/core.md","filePath":"zh/start/core.md","lastUpdated":1701780435000}'),t={name:"zh/start/core.md"};function d(n,e,r,i,y,E){return c(),l("div",null,[...e[0]||(e[0]=[p('<p>欢迎来到 Base JS SDK 文档，本章节将为你介绍，如何开发一个 Base 插件，并掌握 Base 插件开发的 80% 概念以及设计的核心概念。 <a href="https://www.npmjs.com/package/@lark-base-open/js-sdk" target="_blank" rel="noreferrer">NPM 地址</a></p><p>前置学习：</p><ul><li>前端开发基础知识：HTMl / CSS / JS</li><li><a href="https://react.docschina.org/learn" target="_blank" rel="noreferrer">React</a> (不限定 UI 框架使用 Vue 等框架的同学也可以制作插件)</li></ul><p>推荐学习：</p><ul><li><a href="https://www.typescriptlang.org/docs/" target="_blank" rel="noreferrer">Typescript</a></li></ul><h1 id="核心知识" tabindex="-1">核心知识 <a class="header-anchor" href="#核心知识" aria-label="Permalink to &quot;核心知识&quot;">​</a></h1><p>我们先了解一下多维表格的核心概念以及相关知识</p><p>下图所示的是 API 的设计模型:</p><p><img src="'+o+`" alt=""></p><p><code>bitable</code>是 API 的入口，<code>base</code> <code>ui</code> <code>bridge</code> 等模块都会作为属性挂载在上面，一般会这样使用:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">import</span><span style="color:#E1E4E8;"> { bitable } </span><span style="color:#F97583;">from</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">&#39;@lark-base-open/js-sdk&#39;</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">table</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> bitable.base.</span><span style="color:#B392F0;">getActiveTable</span><span style="color:#E1E4E8;">();</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">attachmentFieldList</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">await</span><span style="color:#E1E4E8;"> table.</span><span style="color:#B392F0;">getFieldListByType</span><span style="color:#E1E4E8;">&lt;</span><span style="color:#B392F0;">IAttachmentField</span><span style="color:#E1E4E8;">&gt;(FieldType.Attachment);</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">import</span><span style="color:#24292E;"> { bitable } </span><span style="color:#D73A49;">from</span><span style="color:#24292E;"> </span><span style="color:#032F62;">&#39;@lark-base-open/js-sdk&#39;</span></span>
<span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">table</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> bitable.base.</span><span style="color:#6F42C1;">getActiveTable</span><span style="color:#24292E;">();</span></span>
<span class="line"><span style="color:#D73A49;">const</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">attachmentFieldList</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> </span><span style="color:#D73A49;">await</span><span style="color:#24292E;"> table.</span><span style="color:#6F42C1;">getFieldListByType</span><span style="color:#24292E;">&lt;</span><span style="color:#6F42C1;">IAttachmentField</span><span style="color:#24292E;">&gt;(FieldType.Attachment);</span></span></code></pre></div><p>其中，<code>table</code> <code>field</code> 等模块都都可以在下面这张图中找到对应的关系：</p><p><img src="`+s+'" alt=""></p><p>下面介绍各个模块的概念：</p><ul><li><p><code>base</code>: <code>base</code> 模块，可以理解为多个 <code>table</code>的集合体，可以通过 API 来获取对应的<code>table</code>，其中还有文件上传等 API 应用层面的 API</p></li><li><p><code>table</code>: <code>table</code> 模块是数据的集合体，不涉及页面上<code>UI</code>的展示，其概念和数据库中的表类似:含有<code>field(字段) record(记录)</code>，在多维表格中，<code>table</code> 还会含有 <code>view(视图)</code>的概念（在 <code>table</code> 层面获取字段信息的时候，往往是无序的，因为<code>table</code>层面只有数据，无法知晓其在<code>view(视图)</code>层面的展示方式）</p></li><li><p><code>field</code>: <code>field</code> 模块中含有很多不同的字段类型，例如：<code>IAttachmentField(附件字段)</code> 以及后续我们要用到的<code>ICurrencyField(货币字段)</code>等，<code>Field</code>字段细化了很多字段的操作方法以及设置字段属性的方法，例如为多选/单选字段提供了新增选项的方法，详细方法可以看对应的 API 文档，同时我们也推荐用户从字段入手结合 <code>record</code> 来对数据进行增删改查，以及获取 <code>table</code> 的 <code>cell</code> 或者通过 <code>createCell</code> 方法来创建一个 <code>cell</code></p></li><li><p><code>record</code>: <code>record</code> 模块主要是用来获取数据的，其可以和 <code>field</code> 共同作用来获取 <code>cell</code></p></li><li><p><code>cell</code>: <code>cell</code> 模块是的单元格，是 <code>record</code>/<code>field</code> 中的某一个单元格的数据，同时支持用户通过调用<code>field</code>的 <code>createCell</code> 方法来创建一个单元格，创建好的单元格可以在 <code>table.addRecord</code> 时作为参数传入进去，从而新增一条数据，在调用 <code>createCell</code> 方法时，为了便于开 发者调用，会简化对应的数据结构，创建的单元格被插入到 <code>table</code> 之后，会与一条 <code>record</code> 自动关联起来，在与 <code>record</code> 关联之后，<code>cell</code> 的 <code>getValue/setValue</code> 方法就会与 <code>table</code> 的数据关联起来，从而具有实时性</p></li><li><p><code>view</code>: <code>view</code> 模块是视图模块，其最主要的作用就是在当前视图（表格视图/看板视图）决定 <code>table</code> 中 <code>field(字段)/record(记录)</code> 的展示方式（顺序/是否可见），因此在 <code>view</code> 层中，去获取 <code>field(字段)/record(记录)</code> 的字段信息/记录顺序，往往都是与当前展现的内容相符合的（<code>table</code>层去获取这些信息的时候，往往会因为 <code>table</code> 层无法决定展现形式而无序）</p></li><li><p><code>ui</code>: <code>ui</code> 模块负责插件展示窗口 UI 的 API，与插件本身的应用能力有关</p></li><li><p><code>bridge</code>: <code>bridge</code> 模块主要提供应用层的接口，提供类似主题切换事件通知等插件能力的 API，与 <code>UI</code> 模块类似，都与应用能力有关系</p></li></ul><p>接下来，我们搭建开发环境。</p>',16)])])}const f=a(t,[["render",d]]);export{h as __pageData,f as default};
